-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "المسلم الجديد" (muslim-jadid) — تستنفد العنقود بالكامل (7 تصنيفات
-- فرعية من أصل 7، كلها بلا محتوى): التعريف بالإسلام، الشهادتان، الأركان
-- العملية، الوضوء والصلاة عمليًا، الأذكار الأساسية، الحلال والحرام،
-- برنامج تدرجي (٧/٣٠/٩٠ يومًا).
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: ماذا يعني انتمائي
-- للإسلام لمحمد قطب، الأصول الثلاثة لمحمد بن عبد الوهاب، فقه السنة
-- لسيد سابق، صفة صلاة النبي للألباني، حصن المسلم للقحطاني، الحلال
-- والحرام في الإسلام ليوسف القرضاوي، دليل المسلم الجديد لفهد بن سالم
-- باهمام.
-- الآيات المستشهَد بها (آل عمران: 19، محمد: 19، المائدة: 6، الرعد: 28،
-- المائدة: 87، البقرة: 286) تحقَّقت حرفياً من
-- artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah قبل
-- الإدراج.
-- الأحاديث تحقَّقت عبر WebSearch قبل الإدراج: حديث جبريل عن الإسلام
-- والإيمان والإحسان (رواه مسلم، عن عمر بن الخطاب)، «بني الإسلام على
-- خمس» (متفق عليه، عن ابن عمر)، «صلوا كما رأيتموني أصلي» (رواه
-- البخاري، عن مالك بن الحويرث)، «مثل الذي يذكر ربه والذي لا يذكر ربه
-- مثل الحي والميت» (رواه البخاري، عن أبي موسى الأشعري)، دعاء «اللهم بك
-- أصبحنا وبك أمسينا» (رواه الترمذي وأبو داود، عن أبي هريرة)، «إن
-- الحلال بيّن وإن الحرام بيّن» (متفق عليه، عن النعمان بن بشير)، وحديث
-- بعث معاذ بن جبل إلى اليمن (متفق عليه، عن ابن عباس، سبق تحقُّقه في
-- دفعة dawah).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات السبعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) التعريف بالإسلام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='29d96d39-13e7-47f5-b253-d974a283bf1f' AND title='التعريف بالإسلام: أركانه الثلاثة الكبرى — الإسلام والإيمان والإحسان') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التعريف بالإسلام: أركانه الثلاثة الكبرى — الإسلام والإيمان والإحسان', 'تعريف موجز بمعنى الإسلام ومراتب الدين الثلاث كما بيّنها النبي صلى الله عليه وسلم في حديث جبريل', '29d96d39-13e7-47f5-b253-d974a283bf1f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الإسلام', 'الإسلام لغة: الاستسلام والانقياد. واصطلاحًا: الاستسلام لله بالتوحيد، والانقياد له بالطاعة، والبراءة من الشرك وأهله. وهو الدين الذي ارتضاه الله لعباده وختم به الرسالات، وبه يدخل المرء في دائرة الأمة الإسلامية.', 1),
    (v_lesson, 'terms', 'مراتب الدين الثلاث', 'بيّن النبي صلى الله عليه وسلم في حديث جبريل عليه السلام أن الدين يقوم على ثلاث مراتب متكاملة: الإسلام، وهو الأعمال الظاهرة من شهادة وصلاة وزكاة وصوم وحج؛ والإيمان، وهو التصديق الباطن بأركانه الستة؛ والإحسان، وهو أعلى المراتب، وهو مراقبة الله في العبادة كأن المرء يراه.', 2),
    (v_lesson, 'evidence', 'الإسلام هو الدين عند الله', 'قال تعالى: ﴿إِنَّ الدِّينَ عِندَ اللَّهِ الْإِسْلَامُ﴾ (آل عمران: 19)', 3),
    (v_lesson, 'evidence', 'حديث جبريل عليه السلام', 'عن عمر بن الخطاب رضي الله عنه قال: بينما نحن جلوس عند رسول الله صلى الله عليه وسلم ذات يوم، إذ طلع علينا رجل شديد بياض الثياب، شديد سواد الشعر، لا يُرى عليه أثر السفر، ولا يعرفه منا أحد، حتى جلس إلى النبي صلى الله عليه وسلم فأسند ركبتيه إلى ركبتيه، ووضع كفيه على فخذيه، وقال: يا محمد أخبرني عن الإسلام، فقال: "الإسلام أن تشهد أن لا إله إلا الله وأن محمدًا رسول الله، وتقيم الصلاة، وتؤتي الزكاة، وتصوم رمضان، وتحج البيت إن استطعت إليه سبيلاً"، قال: صدقت. قال: فأخبرني عن الإيمان، قال: "أن تؤمن بالله وملائكته وكتبه ورسله واليوم الآخر، وتؤمن بالقدر خيره وشره"، قال: فأخبرني عن الإحسان، قال: "أن تعبد الله كأنك تراه، فإن لم تكن تراه فإنه يراك"، رواه مسلم.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'ماذا يعني انتمائي للإسلام — محمد قطب', 1);
  END IF;

  -- 2) الشهادتان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='22f545b6-bef0-4662-badb-1fe9d046ef27' AND title='معنى الشهادتين: لا إله إلا الله محمد رسول الله') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('معنى الشهادتين: لا إله إلا الله محمد رسول الله', 'تعريف موجز بمعنى شهادة أن لا إله إلا الله وأن محمدًا رسول الله وما تقتضيانه', '22f545b6-bef0-4662-badb-1fe9d046ef27', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'معنى شهادة أن لا إله إلا الله', 'نفي الألوهية عن كل ما سوى الله عز وجل، وإثباتها لله وحده؛ فلا معبود بحق إلا الله. وهذا يقتضي إفراد الله تعالى بجميع أنواع العبادة من دعاء وذبح ونذر وخوف ورجاء وتوكل، وترك عبادة ما سواه من الأصنام أو القبور أو غيرها.', 1),
    (v_lesson, 'terms', 'معنى شهادة أن محمدًا رسول الله', 'الإقرار والاعتراف بأن محمد بن عبدالله صلى الله عليه وسلم عبدالله ورسوله إلى الناس كافة، وتصديقه فيما أخبر، وطاعته فيما أمر، واجتناب ما نهى عنه وزجر، وأن لا يُعبد الله إلا بما شرعه على لسانه.', 2),
    (v_lesson, 'evidence', 'الأمر بالعلم بتوحيد الله', 'قال تعالى: ﴿فَاعْلَمْ أَنَّهُ لَا إِلَٰهَ إِلَّا اللَّهُ وَاسْتَغْفِرْ لِذَنبِكَ﴾ (محمد: 19)', 3),
    (v_lesson, 'evidence', 'الشهادتان أول أركان الإسلام', 'عن عبدالله بن عمر بن الخطاب رضي الله عنهما قال: سمعت رسول الله صلى الله عليه وسلم يقول: "بني الإسلام على خمس: شهادة أن لا إله إلا الله وأن محمدًا رسول الله، وإقام الصلاة، وإيتاء الزكاة، وحج البيت، وصوم رمضان"، رواه البخاري ومسلم.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأصول الثلاثة — محمد بن عبد الوهاب', 1);
  END IF;

  -- 3) الأركان العملية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='babaf996-df9a-41c9-a69a-e8f2504fd665' AND title='الأركان العملية للإسلام: الصلاة والزكاة والصوم والحج') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأركان العملية للإسلام: الصلاة والزكاة والصوم والحج', 'تعريف موجز بالأركان العملية الأربعة التي يقوم عليها الإسلام بعد الشهادتين', 'babaf996-df9a-41c9-a69a-e8f2504fd665', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الأركان الأربعة بعد الشهادتين', 'إقامة الصلوات الخمس المفروضة في اليوم والليلة، وإيتاء الزكاة الواجبة على من ملك النصاب وحال عليه الحول، وصيام شهر رمضان، وحج بيت الله الحرام لمن استطاع إليه سبيلاً مرة واحدة في العمر.', 1),
    (v_lesson, 'terms', 'مكانة هذه الأركان', 'هذه الأركان هي الدعائم العملية التي بُني عليها الإسلام بعد الشهادتين، ولا يستقيم إسلام المرء إلا بالمحافظة عليها وأدائها كما شرعها الله، وقد جرت عادة النبي صلى الله عليه وسلم في تعليم المسلم الجديد أن يبدأ بها تدريجيًا بعد استقرار التوحيد في قلبه.', 2),
    (v_lesson, 'evidence', 'الأركان العملية في حديث جبريل', 'قال النبي صلى الله عليه وسلم مجيبًا عن سؤال الإسلام: "الإسلام أن تشهد أن لا إله إلا الله وأن محمدًا رسول الله، وتقيم الصلاة، وتؤتي الزكاة، وتصوم رمضان، وتحج البيت إن استطعت إليه سبيلاً"، رواه مسلم عن عمر بن الخطاب رضي الله عنه.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — سيد سابق', 1);
  END IF;

  -- 4) الوضوء والصلاة عمليًا
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='90958256-2dbd-4adc-a2c4-ecdb62b04da1' AND title='الوضوء والصلاة عمليًا: كيف يتطهر المسلم الجديد ويصلي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الوضوء والصلاة عمليًا: كيف يتطهر المسلم الجديد ويصلي', 'تعريف موجز بخطوات الوضوء وصفة الصلاة كما علّمها النبي صلى الله عليه وسلم', '90958256-2dbd-4adc-a2c4-ecdb62b04da1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'خطوات الوضوء', 'يبدأ الوضوء بالنية، ثم غسل الوجه، ثم غسل اليدين إلى المرفقين، ثم مسح الرأس، ثم غسل الرجلين إلى الكعبين، مع الترتيب بين هذه الأعضاء والموالاة بينها دون تأخير يُذهب أثر ما قبله.', 1),
    (v_lesson, 'terms', 'صفة الصلاة إجمالًا', 'تبدأ الصلاة بتكبيرة الإحرام، ثم قراءة الفاتحة فما تيسر من القرآن، ثم الركوع فالرفع منه، ثم السجدتان والجلسة بينهما، وتُعاد هذه الأركان في كل ركعة، وتُختم الصلاة بالتشهد والسلام؛ وقد أمر النبي صلى الله عليه وسلم أن تُؤدى الصلاة على هيئته كما رآه المصلون يصلي.', 2),
    (v_lesson, 'evidence', 'الأمر بالوضوء قبل الصلاة', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ﴾ (المائدة: 6)', 3),
    (v_lesson, 'evidence', 'الأمر بالاقتداء بصلاة النبي صلى الله عليه وسلم', 'عن مالك بن الحويرث رضي الله عنه قال: أتينا النبي صلى الله عليه وسلم ونحن شببة متقاربون، فأقمنا عنده عشرين يومًا وليلة، فلما ظن أنّا قد اشتقنا إلى أهلنا سألنا عمن تركنا بعدنا فأخبرناه، فقال: "ارجعوا إلى أهليكم فأقيموا فيهم وعلّموهم ومروهم... وصلّوا كما رأيتموني أصلي"، رواه البخاري.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'صفة صلاة النبي صلى الله عليه وسلم — محمد ناصر الدين الألباني', 1);
  END IF;

  -- 5) الأذكار الأساسية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2ca2bc1a-ad19-4817-9b77-f214056d80f6' AND title='الأذكار الأساسية للمسلم الجديد: فضل الذكر وأذكار الصباح والمساء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأذكار الأساسية للمسلم الجديد: فضل الذكر وأذكار الصباح والمساء', 'تعريف موجز بفضل ذكر الله وأهم الأذكار اليومية التي يبدأ بها المسلم الجديد', '2ca2bc1a-ad19-4817-9b77-f214056d80f6', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'فضل الذكر', 'ذكر الله تعالى من أعظم العبادات وأيسرها على المسلم، فهو قول باللسان وذكر بالقلب يطمئن به المؤمن ويستحضر معه معية الله له في كل حال، ويستطيع كل مسلم أن يلازمه في أي وقت وعلى أي حال كان عليها.', 1),
    (v_lesson, 'terms', 'أذكار الصباح والمساء', 'من أهم ما يبدأ به المسلم الجديد أذكار الصباح والمساء، وهي أدعية مأثورة يقولها المسلم في أول النهار وآخره، يستعين بها على طاعة الله ويستحضر بها افتقاره إليه سبحانه وحفظه له.', 2),
    (v_lesson, 'evidence', 'ذكر الله سبب لطمأنينة القلوب', 'قال تعالى: ﴿الَّذِينَ آمَنُوا وَتَطْمَئِنُّ قُلُوبُهُم بِذِكْرِ اللَّهِ أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ﴾ (الرعد: 28)', 3),
    (v_lesson, 'evidence', 'مثل الذاكر وغير الذاكر', 'عن أبي موسى الأشعري رضي الله عنه أن النبي صلى الله عليه وسلم قال: "مثل الذي يذكر ربه والذي لا يذكر ربه مثل الحي والميت"، رواه البخاري.', 4),
    (v_lesson, 'evidence', 'دعاء الصباح والمساء', 'عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم كان يعلّمهم أن يقولوا إذا أصبحوا: "اللهم بك أصبحنا، وبك أمسينا، وبك نحيا، وبك نموت، وإليك النشور"، رواه الترمذي وأبو داود.', 5);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'حصن المسلم من أذكار الكتاب والسنة — سعيد بن علي بن وهف القحطاني', 1);
  END IF;

  -- 6) الحلال والحرام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0b4b9a5b-588a-43b7-b3ba-0eeff465913e' AND title='أساسيات الحلال والحرام في الإسلام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أساسيات الحلال والحرام في الإسلام', 'تعريف موجز بضابط الحلال والحرام في الإسلام وأهمية اجتناب الشبهات', '0b4b9a5b-588a-43b7-b3ba-0eeff465913e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الأصل في الأشياء الإباحة', 'الأصل في الأطعمة والأشربة والمعاملات الإباحة، وقد أحل الله لعباده الطيبات وحرّم عليهم الخبائث؛ فما ورد نص صريح بتحريمه فهو حرام، وما عدا ذلك فهو على أصل الإباحة.', 1),
    (v_lesson, 'terms', 'الحلال البيّن والحرام البيّن والمشتبهات', 'تنقسم الأمور من حيث الحل والحرمة إلى ثلاثة أقسام: حلال بيّن واضح، وحرام بيّن واضح، وأمور مشتبهة لا يعلم كثير من الناس حكمها؛ والأحوط للمسلم الجديد أن يتقي هذه المشتبهات حفظًا لدينه وعرضه.', 2),
    (v_lesson, 'evidence', 'النهي عن تحريم الطيبات', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ﴾ (المائدة: 87)', 3),
    (v_lesson, 'evidence', 'الحلال بيّن والحرام بيّن', 'عن النعمان بن بشير رضي الله عنهما قال: سمعت رسول الله صلى الله عليه وسلم يقول: "إن الحلال بيّن، وإن الحرام بيّن، وبينهما مشتبهات لا يعلمهن كثير من الناس، فمن اتقى الشبهات استبرأ لدينه وعرضه، ومن وقع في الشبهات وقع في الحرام..."، متفق عليه.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الحلال والحرام في الإسلام — يوسف القرضاوي', 1);
  END IF;

  -- 7) برنامج تدرجي (٧/٣٠/٩٠ يومًا)
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='251c8db5-d3ad-4967-9530-3b61f2abaebf' AND title='برنامج تدرجي لتعلم أساسيات الإسلام: منهج النبي صلى الله عليه وسلم في التدرج') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('برنامج تدرجي لتعلم أساسيات الإسلام: منهج النبي صلى الله عليه وسلم في التدرج', 'تعريف موجز بمنهج التدرج النبوي في تعليم المسلم الجديد أصول دينه خطوة خطوة', '251c8db5-d3ad-4967-9530-3b61f2abaebf', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أساس التدرج في التعليم', 'منهج النبي صلى الله عليه وسلم في تعليم من دخل الإسلام حديثًا هو التدرج، فيبدأ بالأصل الأعظم وهو التوحيد وشهادة أن لا إله إلا الله، ثم ينتقل إلى الصلاة، ثم إلى بقية الأركان والشرائع بحسب طاقة المتعلم واستعداده، دون إثقال عليه بجميع الأحكام دفعة واحدة.', 1),
    (v_lesson, 'terms', 'مراعاة الطاقة والتيسير', 'راعى الشرع في تكاليفه طاقة الإنسان ولم يحمّله ما لا يسعه، فيسع المسلم الجديد أن يتعلم دينه تدريجيًا يومًا بعد يوم بحسب استطاعته، مبتدئًا بالضروريات ثم منتقلًا إلى ما بعدها بثبات دون استعجال.', 2),
    (v_lesson, 'evidence', 'عدم تكليف النفس فوق طاقتها', 'قال تعالى: ﴿لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا﴾ (البقرة: 286)', 3),
    (v_lesson, 'evidence', 'منهج التدرج في تعليم معاذ لأهل اليمن', 'عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم لما بعث معاذًا رضي الله عنه إلى اليمن قال له: "إنك تأتي قومًا من أهل الكتاب، فليكن أول ما تدعوهم إليه شهادة أن لا إله إلا الله، فإن هم أطاعوا لذلك فأعلمهم أن الله قد افترض عليهم خمس صلوات في كل يوم وليلة..."، متفق عليه.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'دليل المسلم الجديد — فهد بن سالم باهمام', 1);
  END IF;

